"use strict";(self.webpackChunk_servicenow_sdk_docs=self.webpackChunk_servicenow_sdk_docs||[]).push([["533022"],{539143(e){e.exports=JSON.parse('{"tag":{"label":"sys_id","permalink":"/sdk/4.8.1/tags/sys-id","allTagsPath":"/sdk/4.8.1/tags","count":6,"items":[{"id":"api/table/columns/guidcolumn-api","title":"GuidColumn","description":"A Column for a GUID (Globally Unique Identifier) type field.","permalink":"/sdk/4.8.1/api/table/columns/guidcolumn-api"},{"id":"fluent/now-del-guide","title":"Now.del","description":"Marks a record for deletion. When the application is deployed, records marked with Now.del() will be removed from the target instance.","permalink":"/sdk/4.8.1/fluent/now-del-guide"},{"id":"fluent/now-id-guide","title":"Now.ID","description":"Now.ID[\'key-name\'] gives a Fluent record a stable, human-readable identity. Use it to assign the $id property on any API that accepts one \u2014 the build system maps the key to a real sys_id and keeps it stable across builds.","permalink":"/sdk/4.8.1/fluent/now-id-guide"},{"id":"fluent/now-ref-guide","title":"Now.ref","description":"Now.ref() creates a reference to a record in another table. Use it when a field needs to point to a record that isn\'t defined in the current file \u2014 for example, referencing a role, a flow, or any record identified by its sys_id or coalesce keys.","permalink":"/sdk/4.8.1/fluent/now-ref-guide"},{"id":"guides/query-guide","title":"Querying the Instance","description":"now-sdk query runs a read-only Table REST API query against the authenticated ServiceNow instance. Use it for live, instance-specific data \u2014 column metadata, existing sys_ids, choice values, role memberships, scope info, etc.","permalink":"/sdk/4.8.1/guides/query-guide"},{"id":"config/keys-file","title":"The keys.ts File","description":"Every Fluent project has an auto-generated keys.ts file that maps human-readable identifiers to ServiceNow sys_ids. It\'s the registry that makes Now.ID[\'my-record\'] work.","permalink":"/sdk/4.8.1/config/keys-file"}],"unlisted":false}}')}}]);